Method.Source:
/// <summary>
/// update design for custom fields
/// </summary>
/// <returns>int</returns>
public int active()
{
    boolean isTermoFeatureEnabled;

    int ret = next active();

    if(VendParameters::find().ETGEnableTermoNumberFeature == NoYes::Yes)
    {
        isTermoFeatureEnabled = true;
    }
    //NS, DLT, 04/03/2025 MARK ETG_BLnumber, ETG_BLDate FIELDS AS "MANDATORY".
    if (ETGACFParameters::find().BLNumberAutomation == NoYes::Yes
         && ETGCanadaParameters::find().EnableUATSmall != NoYes::Yes)
    {
        this.object(fieldNum(VendInvoiceInfoTable, ETG_BLnumber)).mandatory(true);
        this.object(fieldNum(VendInvoiceInfoTable, ETG_BLDate)).mandatory(true);
    }
    //NE, DLT, 04/03/2025 MARK ETG_BLnumber, ETG_BLDate FIELDS AS "MANDATORY".
    this.object(fieldNum(VendInvoiceInfoTable, ETGTERMONumber)).visible(isTermoFeatureEnabled);
    this.object(fieldNum(VendInvoiceInfoTable, ETGMotherTERMOReference)).visible(isTermoFeatureEnabled);
    this.object(fieldNum(VendInvoiceInfoTable, ETGRemainingTermoValueReal)).visible(isTermoFeatureEnabled);

    return ret;
}
